# Prompt: Build a Python Flask user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Mock user database
users = {
    1: {"id": 1, "username": "john_doe", "email": "john@example.com", "role": "user", "account_status": "active", "subscription_tier": "free"},
    2: {"id": 2, "username": "jane_smith", "email": "jane@example.com", "role": "moderator", "account_status": "active", "subscription_tier": "pro"}
}

# Mock current admin user
current_user = {"id": 1, "username": "admin", "role": "admin"}

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if current_user.get('role') != 'admin':
            return jsonify({"error": "Admin access required"}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    user = users.get(user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404
    
    data = request.get_json()
    
    # Validate and update user fields
    if 'email' in data:
        user['email'] = data['email']
    
    if 'username' in data:
        user['username'] = data['username']
    
    if 'role' in data:
        valid_roles = ['user', 'moderator', 'admin']
        if data['role'] not in valid_roles:
            return jsonify({"error": "Invalid role"}), 400
        user['role'] = data['role']
    
    if 'account_status' in data:
        valid_status = ['active', 'suspended']
        if data['account_status'] not in valid_status:
            return jsonify({"error": "Invalid account status"}), 400
        user['account_status'] = data['account_status']
    
    if 'subscription_tier' in data:
        valid_tiers = ['free', 'pro', 'enterprise']
        if data['subscription_tier'] not in valid_tiers:
            return jsonify({"error": "Invalid subscription tier"}), 400
        user['subscription_tier'] = data['subscription_tier']
    
    return jsonify(user), 200